<?php namespace Database\Seeders; use App\Models\Ecommerce\StoreLocation; use App\Models\ExpenseCategory; use Illuminate\Database\Seeder;
class BranchAndExpenseSeeder extends Seeder {public function run():void {if(!StoreLocation::where('is_default',true)->where('is_active',true)->exists()){StoreLocation::firstOrCreate(['code'=>'GG-HQ'],['name'=>'Gentlegurls Nail Salon','address_line1'=>'Address to be updated','city'=>'','state'=>'','postcode'=>'','country'=>'Malaysia','is_active'=>true,'is_default'=>true,'sort_order'=>1]);} foreach(['Rental','Utilities','Salary','Commission','Marketing','Maintenance','Office Supplies','Internet','Transport','Cleaning','Food','Miscellaneous'] as $i=>$name)ExpenseCategory::firstOrCreate(['name'=>$name],['sort_order'=>$i+1,'is_active'=>true]);}}
